var flipgame = function(fronts, backs) {
    const same = new Set();
    for (let i = 0; i < fronts.length; i++) {
        if (fronts[i] === backs[i]) same.add(fronts[i]);
    }
    let best = 0;
    for (const v of fronts.concat(backs)) {
        if (!same.has(v)) {
            best = best === 0 ? v : Math.min(best, v);
        }
    }
    return best;
};
